   280→
   281→export default function HomeScreen() {
   282→  const { width } = useWindowDimensions();
   283→  const BANNER_W = width - 32;
   284→  const insets = useSafeAreaInsets();
   285→  const scrollRef = useRef<FlatList>(null);
   286→  const [activeBanner, setActiveBanner] = useState(0);
